import React, { useEffect, useState } from "react";
import axios from "axios";
import InternshipCard from "../components/InternshipCard";
import InternshipModal from "../components/InternshipModal";
import "./Internship.css";

const Internship = () => {
  const [internships, setInternships] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const [applications, setApplications] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const user = JSON.parse(localStorage.getItem("user"));
  const userRole = user?.role;

  // Fetch internships
  const fetchInternships = async () => {
    try {
      const res = await axios.get("/api/internships");
      setInternships(res.data);
    } catch (err) {
      console.error("Error fetching internships:", err);
    }
  };

  // Fetch student's applications
  const fetchApplications = async () => {
    try {
      const res = await axios.get("/api/internships/my-applications", {
        headers: { Authorization: `Bearer ${user.token}` },
      });
      setApplications(res.data || []);
    } catch (err) {
      console.error("Error fetching applications:", err);
    }
  };

  const getApplicationStatus = (internshipId) => {
    const app = applications.find((a) => a.internship === internshipId);
    return app?.status || "Not Applied";
  };

  const handleApply = async (id) => {
    try {
      await axios.post(
        `/api/internships/${id}/apply`,
        {},
        {
          headers: { Authorization: `Bearer ${user.token}` },
        }
      );
      fetchApplications();
      alert("Applied successfully!");
    } catch (err) {
      console.error("Apply failed", err);
      alert("You might have already applied.");
    }
  };

  const handleSaveInternship = async (data) => {
    try {
      const headers = { Authorization: `Bearer ${user.token}` };

      if (editData) {
        await axios.put(`/api/internships/${editData._id}`, data, { headers });
      } else {
        await axios.post("/api/internships", data, { headers });
      }

      setEditData(null);
      setShowModal(false);
      fetchInternships();
    } catch (err) {
      console.error("Error saving internship:", err);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this internship?")) {
      try {
        await axios.delete(`/api/internships/${id}`, {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        fetchInternships();
      } catch (err) {
        console.error("Error deleting internship:", err);
      }
    }
  };

  useEffect(() => {
    fetchInternships();
    if (userRole === "Student") {
      fetchApplications();
    }
  }, []);

  // Filter internships
  const filteredInternships = internships.filter((intern) =>
    intern.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  console.log("Internships:", internships);

  return (
    <div className="internship-page">
      <div className="internship-header">
        <h1>Internships</h1>

        <div className="internship-actions">
          <input
            type="text"
            placeholder="Search internships..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="search-box"
          />
          {(userRole === "Admin" || userRole === "HR") && (
            <button className="add-btn" onClick={() => setShowModal(true)}>
              + Add Internship
            </button>
          )}
        </div>
      </div>

      <div className="internship-list">
        {filteredInternships.length === 0 ? (
          <p>No internships found.</p>
        ) : (
          filteredInternships.map((item) => (
            <InternshipCard
              key={item._id}
              internship={item}
              userRole={userRole}
              applicationStatus={getApplicationStatus(item._id)}
              onApply={handleApply}
              onEdit={(data) => {
                setEditData(data);
                setShowModal(true);
              }}
              onDelete={handleDelete}
            />
          ))
        )}
      </div>

      {showModal && (
        <InternshipModal
          show={showModal}
          onClose={() => {
            setEditData(null);
            setShowModal(false);
          }}
          onSave={handleSaveInternship}
          initialData={editData}
        />
      )}
    </div>
  );
};

export default Internship;
